#include <stdio.h>
#define MAX_VELICINA 1001

void unesi(char niz[], int velicina) {
	char znak = getchar();
	if (znak == '\n') znak = getchar();
	int i = 0;
	while (i < velicina-1 && znak != '\n') {
		niz[i] = znak;
		i++;
		znak = getchar();
	}
	niz[i] = '\0';
}

int main() {
    char tekst[MAX_VELICINA];
    int i = 0, brojRijeci = 0, uRijeci = 0;

    printf("Unesite tekst (do 1000 karaktera): ");
    unesi(tekst, MAX_VELICINA);

    while (tekst[i] != '\0') {
        char c = tekst[i];
        int jeAlfaNum =
            (c >= 'A' && c <= 'Z') ||
            (c >= 'a' && c <= 'z') ||
            (c >= '0' && c <= '9');
        if (jeAlfaNum) {
            if (!uRijeci) {
                brojRijeci++;
                uRijeci = 1;
            }
        } else {
            uRijeci = 0;
        }
        i++;
    }


    printf("Broj rijeci: %d\n", brojRijeci);

    return 0;
}
